import{_ as e,o as a,c as h,f as n}from"./app-4ce8496b.js";const i={},r=n('<ul><li><em>语序</em>: <ul><li><strong>陈述语气</strong>: 主语+谓语+其他</li><li><strong>倒装</strong>: 谓语+主语+其他</li></ul></li></ul><h4 id="only-in-this-way-can-we-improve-english" tabindex="-1"><a class="header-anchor" href="#only-in-this-way-can-we-improve-english" aria-hidden="true">#</a> Only in this way can we improve English</h4><h4 id="倒装的作用-表强调-但不是每个句子都可以倒装-必须在满足定条件下-才能进行相应的倒装。" tabindex="-1"><a class="header-anchor" href="#倒装的作用-表强调-但不是每个句子都可以倒装-必须在满足定条件下-才能进行相应的倒装。" aria-hidden="true">#</a> 倒装的作用：表强调 <mark>但不是每个句子都可以倒装，必须在满足定条件下，才能进行相应的倒装。</mark></h4><h2 id="一-完全倒装-关键词谓语全部-主语-其他" tabindex="-1"><a class="header-anchor" href="#一-完全倒装-关键词谓语全部-主语-其他" aria-hidden="true">#</a> 一，完全倒装：关键词谓语全部+主语+其他</h2><h3 id="_1-表方位的副词位于句首-句子全倒装-there-here-away-out-outside-in-up-down" tabindex="-1"><a class="header-anchor" href="#_1-表方位的副词位于句首-句子全倒装-there-here-away-out-outside-in-up-down" aria-hidden="true">#</a> 1.表方位的副词位于句首，句子全倒装 there,here,away,out/outside,in,up,down</h3><h4 id="out-rushed-the-little-child" tabindex="-1"><a class="header-anchor" href="#out-rushed-the-little-child" aria-hidden="true">#</a> Out rushed the little child</h4><h3 id="_2-表方位的介词短语位于句首-句子全倒装-in-on-at-over-under-across-the-n" tabindex="-1"><a class="header-anchor" href="#_2-表方位的介词短语位于句首-句子全倒装-in-on-at-over-under-across-the-n" aria-hidden="true">#</a> 2.表方位的介词短语位于句首，句子全倒装 in/on/at/over/under/across...+the n.</h3><h4 id="at-the-top-of-the-mountain-stands-a-temple" tabindex="-1"><a class="header-anchor" href="#at-the-top-of-the-mountain-stands-a-temple" aria-hidden="true">#</a> At the top of the mountain stands a temple.</h4><h4 id="注意-当主语是人称代词时-you-i-we-he-she-it-hey-即使有方位副词-介词短语位于句首-也不全倒装" tabindex="-1"><a class="header-anchor" href="#注意-当主语是人称代词时-you-i-we-he-she-it-hey-即使有方位副词-介词短语位于句首-也不全倒装" aria-hidden="true">#</a> 注意：<mark>当主语是人称代词时(you/I/we/he/she/it/hey 即使有方位副词/介词短语位于句首，也不全倒装</mark></h4><h2 id="二-部分倒装-关键词-be情态-助动词-主语-谓语-另一半-其他" tabindex="-1"><a class="header-anchor" href="#二-部分倒装-关键词-be情态-助动词-主语-谓语-另一半-其他" aria-hidden="true">#</a> 二，部分倒装：关键词+be情态/助动词+主语+谓语（另一半)+其他</h2><h3 id="_1-否定副词或短语位于句首时-句子半倒装" tabindex="-1"><a class="header-anchor" href="#_1-否定副词或短语位于句首时-句子半倒装" aria-hidden="true">#</a> 1.否定副词或短语位于句首时，句子半倒装</h3><h4 id="否定词-not-never-nowhere-seldom-little-few-rarely-hardly-scarcely-no-sooner-neither-nor" tabindex="-1"><a class="header-anchor" href="#否定词-not-never-nowhere-seldom-little-few-rarely-hardly-scarcely-no-sooner-neither-nor" aria-hidden="true">#</a> 否定词:not,never,nowhere,seldom,little,few,rarely, hardly,scarcely,no sooner,neither,nor</h4><h4 id="否定短语-in-no-case-in-no-sense-by-no-means-in-no-way-under-no-circumstances-at-no-time-on-no-occasion-on-no-account-绝不" tabindex="-1"><a class="header-anchor" href="#否定短语-in-no-case-in-no-sense-by-no-means-in-no-way-under-no-circumstances-at-no-time-on-no-occasion-on-no-account-绝不" aria-hidden="true">#</a> 否定短语:in no case,in no sense,by no means,.in no way,under no circumstances,at no time,on no occasion, on no account(绝不)</h4><h4 id="never-will-i-give-up-to-difficulties" tabindex="-1"><a class="header-anchor" href="#never-will-i-give-up-to-difficulties" aria-hidden="true">#</a> Never will I give up to difficulties.</h4><ol><li><h4 id="一-就-hardly-scarcely-when-no-sooner-than" tabindex="-1"><a class="header-anchor" href="#一-就-hardly-scarcely-when-no-sooner-than" aria-hidden="true">#</a> <mark>&quot;一...就...”：hardly/scarcely...when ,no sooner...than</mark></h4></li><li><h4 id="hardly-scarcely-no-sooner位于句首-主句半倒。-主句用had-done-从句用did-主倒从不倒" tabindex="-1"><a class="header-anchor" href="#hardly-scarcely-no-sooner位于句首-主句半倒。-主句用had-done-从句用did-主倒从不倒" aria-hidden="true">#</a> <mark>Hardly/Scarcely/No sooner位于句首，主句半倒。 主句用had done,从句用did(主倒从不倒)</mark></h4></li><li><h4 id="hardly-had-i-gone-home-when-it-started-to-rain-heavily" tabindex="-1"><a class="header-anchor" href="#hardly-had-i-gone-home-when-it-started-to-rain-heavily" aria-hidden="true">#</a> <mark>Hardly had I gone home when it started to rain heavily.</mark></h4></li><li><h4 id="not-until-直到-才-not-until位于句首-主句半倒-且时态一般为过去" tabindex="-1"><a class="header-anchor" href="#not-until-直到-才-not-until位于句首-主句半倒-且时态一般为过去" aria-hidden="true">#</a> <mark>not...until“直到.…才”Not until位于句首，主句半倒（且时态一般为过去)</mark></h4></li><li><h4 id="not-only-but-also-不但-而且-not-only位于句首-半倒-前倒后不倒" tabindex="-1"><a class="header-anchor" href="#not-only-but-also-不但-而且-not-only位于句首-半倒-前倒后不倒" aria-hidden="true">#</a> <mark>not only,but(also) “不但.…而且？ Not only位于句首，半倒（前倒后不倒）</mark></h4></li></ol><h3 id="_2-so-such-that-如此-以致于-so-such-所修饰部分位于句首-主句半倒" tabindex="-1"><a class="header-anchor" href="#_2-so-such-that-如此-以致于-so-such-所修饰部分位于句首-主句半倒" aria-hidden="true">#</a> 2.so/such..that“如此.以致于 So/Such+所修饰部分位于句首，主句半倒</h3><h4 id="so-difficult-was-the-exam-that-he-failed-to-pass-it" tabindex="-1"><a class="header-anchor" href="#so-difficult-was-the-exam-that-he-failed-to-pass-it" aria-hidden="true">#</a> So difficult was the exam that he failed to pass it</h4><h3 id="_3-only-状语位于句首-主句半倒" tabindex="-1"><a class="header-anchor" href="#_3-only-状语位于句首-主句半倒" aria-hidden="true">#</a> 3.Only+状语位于句首，主句半倒</h3><ol><li>Only in this way</li><li>can we</li><li>Only if...半倒</li><li>Only when...半倒</li></ol><h3 id="_4-虚拟倒装" tabindex="-1"><a class="header-anchor" href="#_4-虚拟倒装" aria-hidden="true">#</a> 4.虚拟倒装</h3><h4 id="在if引导的非真实条件句中-可以把were-had-助-动词-should提到主句之前-同时省略if。" tabindex="-1"><a class="header-anchor" href="#在if引导的非真实条件句中-可以把were-had-助-动词-should提到主句之前-同时省略if。" aria-hidden="true">#</a> 在if引导的非真实条件句中，可以把were/had(助 动词)/should提到主句之前，同时省略if。</h4><h4 id="were-i-you-i-would-continue-to-study" tabindex="-1"><a class="header-anchor" href="#were-i-you-i-would-continue-to-study" aria-hidden="true">#</a> Were I you,I would continue to study</h4><h2 id="三-特殊倒装" tabindex="-1"><a class="header-anchor" href="#三-特殊倒装" aria-hidden="true">#</a> 三,特殊倒装</h2><h3 id="_1-表-也-和-的确" tabindex="-1"><a class="header-anchor" href="#_1-表-也-和-的确" aria-hidden="true">#</a> 1.表“也”和“的确</h3><h4 id="表肯定-也-so-be-情态-助动词-主语" tabindex="-1"><a class="header-anchor" href="#表肯定-也-so-be-情态-助动词-主语" aria-hidden="true">#</a> 表肯定“也.”：so+be/情态/助动词+主语</h4><h4 id="表否定-也不-neither-nor-be-情态-助动词-主-语" tabindex="-1"><a class="header-anchor" href="#表否定-也不-neither-nor-be-情态-助动词-主-语" aria-hidden="true">#</a> 表否定“也不.”：neither/nor+be/情态/助动词+主 语</h4><h4 id="当前面既有肯定又有否定或有两个谓语动词时-用-so-it-is-with-sb" tabindex="-1"><a class="header-anchor" href="#当前面既有肯定又有否定或有两个谓语动词时-用-so-it-is-with-sb" aria-hidden="true">#</a> 当前面既有肯定又有否定或有两个谓语动词时，用 so it is with sb</h4><h4 id="表-的确-so-主语-be-情态-助动词-只能表肯定" tabindex="-1"><a class="header-anchor" href="#表-的确-so-主语-be-情态-助动词-只能表肯定" aria-hidden="true">#</a> 表“的确”：so+主语+be/情态/助动词（只能表肯定)</h4><h3 id="_2-as表-虽然-必须用倒装语序" tabindex="-1"><a class="header-anchor" href="#_2-as表-虽然-必须用倒装语序" aria-hidden="true">#</a> 2.as表“虽然&quot;必须用倒装语序：</h3><h4 id="adj-adv-n-as-主语-谓语" tabindex="-1"><a class="header-anchor" href="#adj-adv-n-as-主语-谓语" aria-hidden="true">#</a> adj./adv./n.+as+主语+谓语</h4><h4 id="rich-as-he-is-i-don-t-envy-him" tabindex="-1"><a class="header-anchor" href="#rich-as-he-is-i-don-t-envy-him" aria-hidden="true">#</a> Rich as he is,I don&#39;t envy him.</h4>',31),t=[r];function d(o,s){return a(),h("div",null,t)}const c=e(i,[["render",d],["__file","03.倒装.html.vue"]]);export{c as default};
